use anyhow::Result;
use sqlx::PgPool;
use tracing::{error, info};

use super::{calendar, events};
use crate::calendar::CalendarClient;
use crate::email::{EmailGateway, RealEmailGateway};
use crate::models::{EventId, EventType};

/// Smoke-test SMTP connectivity for every configured account. Takes the
/// concrete [`RealEmailGateway`] because `test_connection` is a health-check
/// concern that lives on the real adapter, not on the [`EmailGateway`] seam
/// (which only carries the three business operations: send, build, account).
pub(crate) async fn check_email_connectivity(email_sender: &RealEmailGateway) {
    match email_sender.test_connection().await {
        Ok(_) => info!("Email connectivity checks finished successfully"),
        Err(e) => error!("Email connectivity checks failed: {}", e),
    }
}

pub(crate) async fn renew_calendar_watch(client: &CalendarClient) {
    match calendar::renew_watch(client).await {
        Ok(_) => info!("Calendar watch has been renewed"),
        Err(e) => error!("Error renewing calendar watch: {}", e),
    }
}

/// send a reminder email for all events starting next week
pub(crate) async fn send_event_reminders(pool: &PgPool, email_sender: &impl EmailGateway) {
    match events::send_event_reminders(pool, email_sender).await {
        Ok(count) if count > 0 => info!("{} event reminders has been send successfully.", count),
        Ok(_) => (),
        Err(e) => error!("Error while sending event reminders: {}", e),
    }
}

/// Complete all finished events.
pub(crate) async fn close_finished_events(pool: &PgPool, email_sender: &impl EmailGateway) {
    match events::close_finished_running_events(pool, email_sender).await {
        Ok(count) if count > 0 => info!("{count} events has been closed."),
        Ok(_) => (),
        Err(e) => error!("Error while closing finished events: {}", e),
    }
}

/// send a reminder email for all bookings which are due with payment
pub(crate) async fn send_payment_reminders(
    pool: &PgPool,
    event_type: EventType,
    email_sender: &impl EmailGateway,
) -> Result<()> {
    match events::send_payment_reminders(pool, event_type, email_sender).await {
        Ok(count) if count > 0 => {
            info!("{} payment reminders has been send successfully.", count);
            Ok(())
        }
        Ok(_) => Ok(()),
        Err(e) => {
            error!("Error while sending payment reminders: {}", e);
            Err(e)
        }
    }
}

/// send participation confirmation after finished event
pub(crate) async fn send_participation_confirmation(
    pool: &PgPool,
    event_id: EventId,
    email_sender: &impl EmailGateway,
) -> Result<()> {
    match events::send_participation_confirmation(pool, event_id, email_sender).await {
        Ok(count) if count > 0 => {
            info!(
                "{} participation confirmations has been send successfully.",
                count
            );
            Ok(())
        }
        Ok(_) => Ok(()),
        Err(e) => {
            error!("Error while sending participation confirmations: {}", e);
            Err(e)
        }
    }
}

#[cfg(test)]
mod tests {
    use crate::email::MockEmailGateway;
    use anyhow::anyhow;

    /// `check_email_connectivity` wraps a real SMTP health-check. The mock
    /// there lives on the concrete `RealEmailGateway::test_connection`, which
    /// is intentionally not on the trait; the wrapping itself (log on Ok/Err)
    /// is exercised end-to-end against the real adapter only. The two
    /// offline tests below cover the two reminder paths that *do* go through
    /// the [`EmailGateway`] seam.
    #[tokio::test]
    async fn test_send_event_reminders_empty_db_is_ok() {
        let mut mock = MockEmailGateway::new();
        mock.expect_send_messages()
            .times(0)
            .returning(|_, _| Box::pin(async { unreachable!() }));
        mock.expect_account()
            .times(0)
            .returning(|_| Box::pin(async { unreachable!() }));

        let pool = sqlx::PgPool::connect_lazy("REDACTED").unwrap();
        let _ = super::send_event_reminders(&pool, &mock).await;
    }

    #[tokio::test]
    async fn test_send_payment_reminders_db_error_propagates() {
        let mut mock = MockEmailGateway::new();
        mock.expect_account()
            .times(0)
            .returning(|_| Box::pin(async { Err(anyhow!("no db")) }));
        mock.expect_send_messages()
            .times(0)
            .returning(|_, _| Box::pin(async { unreachable!() }));

        let pool = sqlx::PgPool::connect_lazy("REDACTED").unwrap();
